import React, { useState, useContext } from 'react';
import {
  Box, Card, CardContent, TextField, Button, Typography,
  Link, Alert, CircularProgress, InputAdornment, IconButton,
} from '@mui/material';
import { Visibility, VisibilityOff } from '@mui/icons-material';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import { loginUser } from '../api';
import { AuthContext } from '../context/AuthContext';

export default function LoginPage() {
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const { data } = await loginUser(form);
      login(data.token);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.msg || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #0f0f1a 0%, #1a1a2e 50%, #16213e 100%)',
        px: 2,
      }}
    >
      {/* Decorative blobs */}
      <Box sx={{
        position: 'fixed', top: '-10%', left: '-10%', width: 400, height: 400,
        borderRadius: '50%', background: 'rgba(108,99,255,0.12)', filter: 'blur(80px)', zIndex: 0,
      }} />
      <Box sx={{
        position: 'fixed', bottom: '-10%', right: '-10%', width: 350, height: 350,
        borderRadius: '50%', background: 'rgba(255,101,132,0.10)', filter: 'blur(80px)', zIndex: 0,
      }} />

      <Card sx={{
        width: '100%', maxWidth: 420, zIndex: 1,
        backdropFilter: 'blur(20px)',
        background: 'rgba(26,26,46,0.85)',
        boxShadow: '0 24px 60px rgba(0,0,0,0.4)',
      }}>
        <CardContent sx={{ p: 4 }}>
          {/* Logo Area */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography variant="h4" sx={{
              background: 'linear-gradient(135deg, #6C63FF, #FF6584)',
              WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
              fontWeight: 800, letterSpacing: '-0.5px',
            }}>
              ConnectSphere
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Welcome back! Sign in to continue.
            </Typography>
          </Box>

          {error && <Alert severity="error" sx={{ mb: 2, borderRadius: 2 }}>{error}</Alert>}

          <Box component="form" onSubmit={handleSubmit} noValidate>
            <TextField
              fullWidth label="Email Address" name="email" type="email"
              value={form.email} onChange={handleChange}
              required autoComplete="email" sx={{ mb: 2 }}
            />
            <TextField
              fullWidth label="Password" name="password"
              type={showPassword ? 'text' : 'password'}
              value={form.password} onChange={handleChange}
              required autoComplete="current-password" sx={{ mb: 3 }}
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton onClick={() => setShowPassword(!showPassword)} edge="end">
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />
            <Button
              type="submit" fullWidth variant="contained" size="large"
              disabled={loading || !form.email || !form.password}
              sx={{ mb: 2, py: 1.4 }}
            >
              {loading ? <CircularProgress size={22} color="inherit" /> : 'Sign In'}
            </Button>
          </Box>

          <Typography align="center" variant="body2" color="text.secondary">
            Don't have an account?{' '}
            <Link component={RouterLink} to="/signup" sx={{ color: '#6C63FF', fontWeight: 600 }}>
              Sign Up
            </Link>
          </Typography>
        </CardContent>
      </Card>
    </Box>
  );
}
